effect.script:
function animate(env,el,p) {
    let absTimeSeconds = env.frame/env.fps;
    let evolution = p.evolution + (absTimeSeconds * p.speed) - p.speed;

    var a = p.angle * (Math.PI / 180);
    var s = Math.sin(a);
    var c = Math.cos(a);


    let dx = AM.simplexNoise(el.transform.location.x + p.seed*54623.245, el.transform.location.y, evolution + p.seed*49235.319798);
    let dy = AM.simplexNoise(el.transform.location.x, el.transform.location.y + p.seed*8723.5647, evolution+7468.329 + p.seed*19337.940385);
    dx *= p.mag;
    dy *= p.mag * p.slack;

    let rx = dx * c - dy * s;
    let ry = dx * s + dy * c;

    el.transform.location.x += rx;
    el.transform.location.y += ry;
    return el;
}
